func newTemplateContext(
	t *templateState,
	lookupFn func(name string) *templateState,
) *templateContext {
	return &templateContext{
		t:			t,
		lookupFn:		lookupFn,
		visited:		make(map[string]bool),
		templateNotFound:	make(map[string]bool),
		deferNodes:		make(map[string]*parse.ListNode),
	}
}
